        public async Task<IOBPv400CreateTransactionRequestAccountOtpApiResponse?> OBPv400CreateTransactionRequestAccountOtpOrDefaultAsync(string bankid, string accountid, string viewid, string accountotp, OBPv400CreateTransactionRequestAccountRequest oBPv400CreateTransactionRequestAccountRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await OBPv400CreateTransactionRequestAccountOtpAsync(bankid, accountid, viewid, accountotp, oBPv400CreateTransactionRequestAccountRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

