        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="viewid">The VIEWID identifier</param>
        /// <param name="counterparty">The COUNTERPARTY identifier</param>
        /// <param name="oBPv400CreateTransactionRequestCounterpartyRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv400CreateTransactionRequestCounterpartyApiResponse"/>&gt;</returns>
        public async Task<IOBPv400CreateTransactionRequestCounterpartyApiResponse?> OBPv400CreateTransactionRequestCounterpartyOrDefaultAsync(string bankid, string accountid, string viewid, string counterparty, OBPv400CreateTransactionRequestCounterpartyRequest oBPv400CreateTransactionRequestCounterpartyRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await OBPv400CreateTransactionRequestCounterpartyAsync(bankid, accountid, viewid, counterparty, oBPv400CreateTransactionRequestCounterpartyRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

