        public async Task<IOBPv400CreateTransactionRequestRefundApiResponse?> OBPv400CreateTransactionRequestRefundOrDefaultAsync(string bankid, string accountid, string viewid, string refund, OBPv400CreateTransactionRequestRefundRequest oBPv400CreateTransactionRequestRefundRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
