        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="ethsendtransaction">The ETHSENDTRANSACTION identifier</param>
        /// <param name="oBPv600CreateTransactionRequestEthereumeSendTransactionRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv600CreateTransactionRequestEthereumeSendTransactionApiResponse"/>&gt;</returns>
        public async Task<IOBPv600CreateTransactionRequestEthereumeSendTransactionApiResponse?> OBPv600CreateTransactionRequestEthereumeSendTransactionOrDefaultAsync(string bankid, string accountid, string ethsendtransaction, OBPv600CreateTransactionRequestEthereumeSendTransactionRequest oBPv600CreateTransactionRequestEthereumeSendTransactionRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await OBPv600CreateTransactionRequestEthereumeSendTransactionAsync(bankid, accountid, ethsendtransaction, oBPv600CreateTransactionRequestEthereumeSendTransactionRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

