        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="hold">The HOLD identifier</param>
        /// <param name="oBPv400CreateTransactionRequestFreeFormRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv600CreateTransactionRequestHoldApiResponse"/>&gt;</returns>
        public async Task<IOBPv600CreateTransactionRequestHoldApiResponse?> OBPv600CreateTransactionRequestHoldOrDefaultAsync(string bankid, string accountid, string hold, OBPv400CreateTransactionRequestFreeFormRequest oBPv400CreateTransactionRequestFreeFormRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await OBPv600CreateTransactionRequestHoldAsync(bankid, accountid, hold, oBPv400CreateTransactionRequestFreeFormRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

